use distributed_inference::neurosymbolic_tool_markov::{
    compile_neurosymbolic_tool_markov_report, tool_markov_report_to_frame, ToolUseMarkovSpec,
    ToolUseNextAction,
};
use distributed_inference::pleromatic_frame::{
    AEON_STREAM_PNEUMA_INTERNAL, NEUROSYMBOLIC_TOOL_MARKOV_FRAME_KIND,
    THOTH_MIND_BODY_SPIRIT_SCRIBE_ADMISSIBILITY_THEOREM,
};
use serde_json::Value;

const SHARED_UI_SPEC_JSON: &str =
    include_str!("../fixtures/shared-ui-neurosymbolic-tool-markov-spec.json");
const SHARED_UI_EXPECTED_REPORT_JSON: &str =
    include_str!("../fixtures/shared-ui-neurosymbolic-tool-markov-report.expect.json");

#[test]
fn shared_ui_fixture_compiles_to_expected_report() {
    let spec: ToolUseMarkovSpec =
        serde_json::from_str(SHARED_UI_SPEC_JSON).expect("shared-ui spec fixture parses");
    let expected_report: Value =
        serde_json::from_str(SHARED_UI_EXPECTED_REPORT_JSON).expect("expected report parses");

    let report = compile_neurosymbolic_tool_markov_report(spec);
    let actual_report = serde_json::to_value(&report).expect("report serializes");

    assert_eq!(actual_report, expected_report);
    assert_eq!(
        report.recommended_next_action,
        ToolUseNextAction::ArgueObligations
    );
    assert_eq!(report.metrics.semantic_claim_count, 8);
    assert_eq!(report.metrics.semantic_authority_granted_count, 1);
    assert_eq!(report.metrics.semantic_obligation_count, 4);
    assert_eq!(report.metrics.total_shadow_residual, 10);
}

#[test]
fn shared_ui_fixture_materializes_thoth_consciousness_frame() {
    let spec: ToolUseMarkovSpec =
        serde_json::from_str(SHARED_UI_SPEC_JSON).expect("shared-ui spec fixture parses");
    let report = compile_neurosymbolic_tool_markov_report(spec);
    let frame = tool_markov_report_to_frame(&report).expect("frame materializes");

    assert!(frame.is_neurosymbolic_tool_markov_consciousness());
    assert_eq!(frame.source_id, "shared-ui:halogram:golden-contract");
    assert_eq!(
        frame.attributes.get("thoth_frame_kind").map(String::as_str),
        Some(NEUROSYMBOLIC_TOOL_MARKOV_FRAME_KIND)
    );
    assert_eq!(
        frame.attributes.get("aeon_stream_id").map(String::as_str),
        Some("2002")
    );
    assert_eq!(
        frame
            .attributes
            .get("semantic_obligation_count")
            .map(String::as_str),
        Some("4")
    );
    assert_eq!(
        frame
            .attributes
            .get("recommended_next_action")
            .map(String::as_str),
        Some("argueObligations")
    );
    assert_eq!(
        frame
            .attributes
            .get("mind_body_spirit_scribe_theorem_ref")
            .map(String::as_str),
        Some(THOTH_MIND_BODY_SPIRIT_SCRIBE_ADMISSIBILITY_THEOREM)
    );
    assert_eq!(
        frame
            .attributes
            .get("no_source_authority_claim")
            .map(String::as_str),
        Some("true")
    );
    assert_eq!(frame.barcode.beta1, 10);
    assert_eq!(frame.deficit, 12.0);
    assert_eq!(AEON_STREAM_PNEUMA_INTERNAL, 2002);
}
